def assess(record: dict) -> str:
    required_fields = {"case_id", "tasks", "slices", "rubric_levels", "holdout"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)
    return "PASS" if ok else "REBUILD_EVAL_DATASET"

valid = {"case_id": "CASO-ICA-050-1A", **{"tasks": 40, "slices": {"normal": 25, "edge": 10, "adversarial": 5}, "rubric_levels": {0, 1, 2, 3}, "holdout": 10}}
invalid = {"case_id": "CASO-ICA-050-1A", **{"tasks": 0, "slices": {"normal": 25, "edge": 10, "adversarial": 5}, "rubric_levels": {0, 1, 2, 3}, "holdout": 10}}
incomplete = dict(valid)
if "holdout" in incomplete:
    del incomplete["holdout"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

